import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Typeset.module.css';

const TypesetRoot = forwardRef<HTMLDivElement, HTMLArkProps<'div'>>(function TypesetRoot(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="typeset"
      data-part="root"
      data-slot="typeset"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const TypesetScroll = forwardRef<HTMLDivElement, HTMLArkProps<'div'>>(function TypesetScroll(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="typeset"
      data-part="scroll"
      data-slot="typeset-scroll"
      className={clsx(styles.scroll, normalizeClassName(className))}
      {...props}
    />
  );
});

const Typeset = Object.assign(TypesetRoot, {
  Root: TypesetRoot,
  Scroll: TypesetScroll,
});

export { Typeset };

@layer ui.components {
  .root {
    box-sizing: border-box;
    color: var(--color-foreground);
    font-family: var(--typeset-font-body, inherit);
    font-size: calc(var(--typeset-size, 1em) * 1.125);
    line-height: var(--typeset-leading, 1.75);
    overflow-wrap: break-word;
  }

  @media (min-width: 48rem), print {
    .root {
      font-size: var(--typeset-size, 1em);
    }
  }

  .root {
    &
      *:not(
        :where(
          :global(.not-typeset),
          [data-not-typeset],
          :global(.not-typeset) *,
          [data-not-typeset] *
        )
      ) {
      &:where(p) {
        margin-block: var(--typeset-flow, 1.25em) 0;
      }

      &:where(h1, h2, h3, h4, h5, h6) {
        color: var(--color-foreground);
        font-family: var(--typeset-font-heading, var(--font-sans));
        font-weight: var(--weight-semibold);
        letter-spacing: -0.02em;
        margin-block-end: 0;
      }

      &:where(h1) {
        font-size: 1.75em;
        line-height: 1.3;
        margin-block-start: var(--typeset-flow, 1.25em);
      }

      &:where(h2) {
        font-size: 1.25em;
        line-height: 1.4;
        margin-block-start: calc(var(--typeset-flow, 1.25em) * 1.4);
      }

      &:where(h3) {
        font-size: 1.125em;
        line-height: 1.45;
        margin-block-start: var(--typeset-flow, 1.25em);
      }

      &:where(h4) {
        font-size: 1em;
        line-height: 1.5;
        margin-block-start: var(--typeset-flow, 1.25em);
      }

      &:where(h5) {
        color: var(--color-muted-foreground);
        font-size: 0.875em;
        font-weight: var(--weight-medium);
        line-height: 1.5;
        margin-block-start: calc(var(--typeset-flow, 1.25em) / 0.875);
      }

      &:where(h6) {
        color: var(--color-muted-foreground);
        font-size: 0.8125em;
        font-weight: var(--weight-medium);
        letter-spacing: 0.08em;
        line-height: 1.5;
        margin-block-start: calc(var(--typeset-flow, 1.25em) / 0.8125);
        text-transform: uppercase;
      }

      &:where([id]) {
        scroll-margin-block-start: var(--typeset-flow, 1.25em);
      }

      &:where(h1 + *, h2 + *, h3 + *, h4 + *, h5 + *, h6 + *) {
        margin-block-start: 1em;
      }

      &:where(a) {
        color: var(--color-primary);
        text-decoration: underline;
        text-decoration-thickness: 0.08em;
        text-underline-offset: 0.15em;
      }

      &:where(ul, ol) {
        margin-block: var(--typeset-flow, 1.25em) 0;
        padding-inline-start: 1.5em;
      }

      &:where(ul) {
        list-style: disc;
      }

      &:where(ol) {
        list-style: decimal;
      }

      &:where(ul ul) {
        list-style: circle;
      }

      &:where(ul ul ul) {
        list-style: square;
      }

      &:where(ol ol) {
        list-style: lower-alpha;
      }

      &:where(ol ol ol) {
        list-style: lower-roman;
      }

      &:where(li)::marker {
        color: var(--color-muted-foreground);
        font-weight: var(--weight-semibold);
      }

      &:where(li + li) {
        margin-block-start: 0.25em;
      }

      &:where(li > ul, li > ol) {
        margin-block-start: 0.5em;
      }

      &:where(:global(ul.contains-task-list)) {
        list-style: none;
        padding-inline-start: 0.25em;
      }

      &:where(:global(li.task-list-item) > input[type='checkbox']) {
        margin-inline-end: 0.5em;
        vertical-align: -0.1em;
        accent-color: var(--color-primary);
      }

      &:where(blockquote) {
        margin-block: var(--typeset-flow, 1.25em) 0;
        margin-inline: 0;
        border-inline-start: var(--border-width-md) solid var(--color-border);
        padding-inline-start: 1em;
        color: var(--color-muted-foreground);
      }

      &:where(:not(pre) > code) {
        padding: 0.1em 0.3em;
        border-radius: var(--radius-sm);
        background: var(--color-muted);
        color: var(--color-foreground);
        font-family: var(--typeset-font-mono, var(--font-mono));
        font-size: 0.875em;
      }

      &:where(pre) {
        max-width: 100%;
        overflow-x: auto;
        margin-block: var(--typeset-flow, 1.25em) 0;
        padding: 1em;
        border: var(--border-width-sm) solid var(--color-border);
        border-radius: var(--radius-md);
        background: var(--color-muted);
        color: var(--color-foreground);
        font-family: var(--typeset-font-mono, var(--font-mono));
        font-size: 0.875em;
        line-height: 1.6;
      }

      &:where(pre > code) {
        padding: 0;
        border-radius: 0;
        background: transparent;
        color: inherit;
        font: inherit;
      }

      &:where(hr) {
        margin-block: var(--typeset-flow, 1.25em) 0;
        border: 0;
        border-block-start: var(--border-width-sm) solid var(--color-border);
      }

      &:where(table) {
        width: 100%;
        max-width: 100%;
        margin-block: var(--typeset-flow, 1.25em) 0;
        border-collapse: separate;
        border-spacing: 0;
        border-block-end: var(--border-width-sm) solid var(--color-border);
        font-size: 1em;
        font-variant-numeric: tabular-nums;
        line-height: 1.5;
      }

      &:where(thead th) {
        padding: 0.65em 1em;
        font-weight: var(--weight-medium);
        text-align: start;
        white-space: nowrap;
      }

      &:where(:is(tbody, tfoot) :is(td, th)) {
        padding: 0.75em 1em;
        border-block-start: var(--border-width-sm) solid var(--color-border);
        text-align: start;
        vertical-align: top;
      }

      &:where(tbody th, tfoot th) {
        font-weight: var(--weight-medium);
      }

      &:where(th:first-child, td:first-child) {
        padding-inline-start: 0;
      }

      &:where(th[align='center'], td[align='center']) {
        text-align: center;
      }

      &:where(th[align='right'], td[align='right']) {
        text-align: end;
      }

      &:where(img, video) {
        display: block;
        max-width: 100%;
        height: auto;
        margin-block: var(--typeset-flow, 1.25em) 0;
        border-radius: var(--radius-md);
      }

      &:where(p img) {
        margin-block-start: 0;
      }

      &:where(figure) {
        margin-block: var(--typeset-flow, 1.25em) 0;
        margin-inline: 0;
      }

      &:where(figcaption, caption) {
        margin-block-start: 0.75em;
        color: var(--color-muted-foreground);
        font-size: 0.875em;
        text-align: center;
      }

      &:where(caption) {
        caption-side: bottom;
      }

      &:where(details) {
        margin-block: var(--typeset-flow, 1.25em) 0;
      }

      &:where(summary) {
        cursor: pointer;
        font-weight: var(--weight-medium);
      }

      &:where(summary)::marker {
        color: var(--color-muted-foreground);
      }

      &:where(dl) {
        margin-block: var(--typeset-flow, 1.25em) 0;
      }

      &:where(dt) {
        margin-block-start: 1em;
        font-weight: var(--weight-medium);
      }

      &:where(dt + dt) {
        margin-block-start: 0.25em;
      }

      &:where(dd) {
        margin-block-start: 0.25em;
        margin-inline-start: 0;
        padding-inline-start: 1em;
        color: var(--color-muted-foreground);
      }

      &:where(:global(.footnotes), [data-footnotes]) {
        margin-block: calc(var(--typeset-flow, 1.25em) * 2) 0;
        border-block-start: var(--border-width-sm) solid var(--color-border);
        padding-block-start: var(--typeset-flow, 1.25em);
        color: var(--color-muted-foreground);
        font-size: 0.875em;
      }
    }
  }

  .root > :where(:first-child):not(:where(:global(.not-typeset), [data-not-typeset])),
  .root
    :where(
      li > :first-child,
      blockquote > :first-child,
      td > :first-child,
      th > :first-child,
      dd > :first-child,
      figure > :first-child,
      figure > picture > img
    ):not(
      :where(
        :global(.not-typeset),
        [data-not-typeset],
        :global(.not-typeset) *,
        [data-not-typeset] *
      )
    ) {
    margin-block-start: 0;
  }

  .scroll {
    max-width: 100%;
    overflow-x: auto;
    margin-block-start: var(--typeset-flow, 1.25em);
    overscroll-behavior-inline: contain;
  }

  .root > .scroll:first-child {
    margin-block-start: 0;
  }

  .root .scroll > * {
    margin-block-start: 0;
  }

  .root .scroll table {
    width: max-content;
    max-width: none;
  }
}
